"""Emission compliance tests for circuit (auto-generated by pact)."""

from circuit.circuit import Circuit


class TestEmissionCompliance:
    """Verify circuit emits structured events correctly."""

    def _make_handler(self):
        events = []
        return events, lambda event: events.append(event)

    def test___init___emits_events(self):
        """Method __init__ emits invoked and completed events."""
        events, handler = self._make_handler()
        obj = Circuit(event_handler=handler)
        try:
            obj.__init__()
        except (TypeError, Exception):
            pass
        invoked = [e for e in events if e.get("event") == "invoked"]
        completed = [e for e in events if e.get("event") in ("completed", "error")]
        assert len(invoked) >= 1, 'No invoked event for __init__'
        assert len(completed) >= 1, 'No completed/error event for __init__'
        assert invoked[0].get("pact_key") == "PACT:circuit:__init__"
        assert isinstance(invoked[0].get("input_classification"), list)

