    def test_pact_key_format(self):
        """All emitted events have correctly formatted PACT keys."""
        events, handler = self._make_handler()
        obj = Circuit(event_handler=handler)
        try:
            obj.__init__()
        except (TypeError, Exception):
            pass
        try:
            obj.run()
        except (TypeError, Exception):
            pass
        try:
            obj.resolve_execution_plan()
        except (TypeError, Exception):
            pass
        try:
            obj.invoke_reviewer()
        except (TypeError, Exception):
            pass
        try:
            obj.get_stage_timeout()
        except (TypeError, Exception):
            pass
        try:
            obj.get_execution_plan()
        except (TypeError, Exception):
            pass
        for event in events:
            key = event.get("pact_key", "")
            assert key.startswith("PACT:circuit:"), f"Bad pact_key: {key}"

    def test_null_handler_no_errors(self):
        """Component works without event_handler — no errors."""
        obj = Circuit()
